import {useEffect,useState} from "react";
import axios from "axios";
import {Pie} from "react-chartjs-2";
import {Chart as ChartJS,ArcElement,Tooltip,Legend} from "chart.js";
import {MapContainer,TileLayer,Marker,Popup} from "react-leaflet";
import "leaflet/dist/leaflet.css";

ChartJS.register(ArcElement,Tooltip,Legend);

export default function PoliceDashboard(){

  const [alerts,setAlerts]=useState([]);
  const [loading,setLoading]=useState(true);
  const [error,setError]=useState("");

  // LOAD ALERTS
  const loadAlerts=()=>{
    axios.get("http://127.0.0.1:8000/api/police-alerts/")
      .then(res=>{
        setAlerts(res.data);
        setLoading(false);
      })
      .catch(()=>{
        setError("Failed to load alerts");
        setLoading(false);
      });
  }

  useEffect(()=>{ loadAlerts(); },[]);

  // ✅ CORRECT RESOLVE FUNCTION
  const resolveAlert=(id)=>{
    axios.post(`http://127.0.0.1:8000/api/resolve-api/${id}/`)
      .then(()=>loadAlerts())
      .catch(err=>console.log("Resolve error:",err));
  }

  const active=alerts.filter(a=>a.status!=="resolved");
  const resolved=alerts.filter(a=>a.status==="resolved");

  if(loading) return <div style={page}>Loading dashboard...</div>;
  if(error) return <div style={page}>{error}</div>;

  return(
    <div style={page}>

      <h1 style={{color:"#2563eb"}}>Police Control Dashboard</h1>

      {/* CHARTS */}
      <div style={chartRow}>
        <div style={chartBox}>
          <Pie data={{
            labels:["Active","Resolved"],
            datasets:[{
              data:[active.length,resolved.length],
              backgroundColor:["#3b82f6","#22c55e"]
            }]
          }}/>
        </div>

        <div style={chartBox}>
          <Pie data={{
            labels:["Low","Medium","High"],
            datasets:[{
              data:[
                count(alerts,"low"),
                count(alerts,"medium"),
                count(alerts,"high")
              ],
              backgroundColor:["#60a5fa","#facc15","#ef4444"]
            }]
          }}/>
        </div>
      </div>

      {/* MAP */}
      <MapContainer
        center={[17.38,78.48]}
        zoom={11}
        style={{height:350,marginTop:30,borderRadius:12,overflow:"hidden"}}
      >
        <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png"/>
        {active.map(a=>(
          a.latitude && a.longitude && (
            <Marker key={a.id} position={[a.latitude,a.longitude]}>
              <Popup>
                <strong>{a.message}</strong><br/>
                Severity: {a.severity||"low"}
              </Popup>
            </Marker>
          )
        ))}
      </MapContainer>

      <h2 style={{marginTop:30}}>Active Alerts</h2>
      <Table alerts={active} resolveAlert={resolveAlert}/>

      <h2 style={{marginTop:30}}>Resolved Alerts History</h2>
      <Table alerts={resolved}/>

    </div>
  )
}

function Table({alerts,resolveAlert}){

  if(!alerts.length){
    return <p style={{marginTop:10}}>No alerts found</p>
  }

  return(
    <table style={table}>
      <thead>
        <tr style={{background:"#f8fafc",textAlign:"left"}}>
          <th style={th}>Device</th>
          <th style={th}>Location</th>
          <th style={th}>Message</th>
          <th style={th}>Status</th>
          <th style={th}>Time</th>
          <th style={th}>Type</th>
          {resolveAlert && <th style={th}>Action</th>}
        </tr>
      </thead>

      <tbody>
      {alerts.map(a=>(
        <tr key={a.id} style={{borderBottom:"1px solid #e2e8f0"}}>
          <td style={td}>{a.device_id}</td>
          <td style={td}>{a.latitude},{a.longitude}</td>
          <td style={td}>{a.message}</td>

          <td style={td}>
            <span style={{
              padding:"4px 8px",
              borderRadius:6,
              background:a.status==="resolved" ? "#16a34a" : "#dc2626",
              color:"white",
              fontSize:12
            }}>
              {a.status}
            </span>
          </td>

          <td style={td}>{new Date(a.timestamp).toLocaleString()}</td>
          <td style={td}>{a.emergency_type}</td>

          {resolveAlert &&
            <td style={td}>
              <button
                style={btn}
                onClick={()=>resolveAlert(a.id)}
              >
                Resolve
              </button>
            </td>
          }
        </tr>
      ))}
      </tbody>
    </table>
  )
}

function count(arr,val){
  return arr.filter(a=>(a.severity||"low").toLowerCase()===val).length;
}

/* ---------- PROFESSIONAL UI STYLES ---------- */

const page={
  padding:30,
  background:"#f1f5f9",
  minHeight:"100vh",
  color:"#0f172a",
  fontFamily:"system-ui, sans-serif"
}

const chartRow={
  display:"flex",
  gap:30,
  flexWrap:"wrap",
  marginTop:20
}

const chartBox={
  width:320,
  background:"white",
  padding:20,
  borderRadius:12,
  boxShadow:"0 4px 12px rgba(0,0,0,0.08)"
}

const table={
  width:"100%",
  marginTop:15,
  borderCollapse:"collapse",
  background:"white",
  borderRadius:12,
  overflow:"hidden",
  boxShadow:"0 4px 12px rgba(0,0,0,0.08)"
}

const th={
  padding:"14px",
  fontSize:14,
  fontWeight:600,
  borderBottom:"1px solid #e2e8f0"
}

const td={
  padding:"12px",
  fontSize:14
}

const btn={
  padding:"6px 14px",
  background:"#2563eb",
  border:"none",
  color:"white",
  borderRadius:6,
  cursor:"pointer",
  fontWeight:500
}
